```class Solution {
public:
    int minAddToMakeValid(string s) {
        int res = 0, bal = 0;
        for (char c : s) {
            bal += (c == '(') ? 1 : -1;
            if (bal < 0) {
                res++;
                bal++;
            }
        }
        return res + bal;
    }
};
```
